## 2. Backend Implementation

### Database Schema (Prisma)

```prisma
// backend/prisma/schema.prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum Priority {
  CRITICAL
  HIGH
  MEDIUM
  LOW
}

enum Source {
  GMAIL
  WHATSAPP
}

enum ActionType {
  REPLY
  ARCHIVE
  FORWARD
  SCHEDULE_MEETING
  DELEGATE
  MARK_DONE
}

model Executive {
  id          String    @id @default(uuid())
  email       String    @unique
  name        String
  preferences Json      @default("{}")
  createdAt   DateTime  @default(now())
  feedItems   FeedItem[]
}

model FeedItem {
  id               String           @id @default(uuid())
  executiveId      String
  executive        Executive        @relation(fields: [executiveId], references: [id])

  // Source
  source           Source
  externalId       String           // Gmail message ID or WhatsApp message ID
  sourceMetadata   Json             // Sender info, thread info, etc.

  // Content
  subject          String
  originalContent  String           @db.Text
  summary          String           @db.Text
  priority         Priority
  priorityScore    Float            // 0.0 - 1.0

  // AI Features
  suggestedReplies SuggestedReply[]
  keyEntities      String[]         // Extracted people, companies, dates

  // Actions
  availableActions ActionType[]
  status           String           @default("UNREAD") // UNREAD, READ, ARCHIVED, DONE

  // Timestamps
  receivedAt       DateTime
  createdAt        DateTime         @default(now())
  updatedAt        DateTime         @updatedAt

  @@index([executiveId, createdAt])
  @@index([priority, createdAt])
  @@index([status])
}

model SuggestedReply {
  id         String   @id @default(uuid())
  feedItemId String
  feedItem   FeedItem @relation(fields: [feedItemId], references: [id], onDelete: Cascade)
  text       String
  tone       String   // professional, casual, urgent
  confidence Float    // AI confidence score
}
```

