### Feed Controller

```typescript
// backend/src/controllers/feedController.ts
import { Request, Response } from 'express';
import { FeedService } from '../services/feedService';
import { prisma } from '../app';

const feedService = new FeedService();

export class FeedController {
  async getFeed(req: Request, res: Response) {
    try {
      const executiveId = req.user?.id; // From auth middleware
      const { 
        priority, 
        source, 
        status = 'UNREAD',
        limit = 50, 
        offset = 0 
      } = req.query;

      const feed = await feedService.getExecutiveFeed({
        executiveId: executiveId as string,
        priority: priority as string,
        source: source as string,
        status: status as string,
        limit: Number(limit),
        offset: Number(offset)
      });

      res.json({
        success: true,
        data: feed.items,
        meta: {
          total: feed.total,
          limit: Number(limit),
          offset: Number(offset),
          hasMore: feed.total > Number(offset) + Number(limit)
        }
      });
    } catch (error) {
      console.error('Error fetching feed:', error);
      res.status(500).json({ success: false, error: 'Failed to fetch feed' });
    }
  }

  async updateItemStatus(req: Request, res: Response) {
    try {
      const { id } = req.params;
      const { status, actionTaken } = req.body;

      const updated = await prisma.feedItem.update({
        where: { id },
        data: { 
          status,
          ...(actionTaken && { 
            sourceMetadata: {
              update: {
                actionTaken,
                actionTimestamp: new Date().toISOString()
              }
            }
          })
        },
        include: {
          suggestedReplies: true
        }
      });

      res.json({ success: true, data: updated });
    } catch (error) {
      res.status(500).json({ success: false, error: 'Failed to update item' });
    }
  }

  async executeAction(req: Request, res: Response) {
    try {
      const { id } = req.params;
      const { actionType, payload } = req.body;

      const result = await feedService.executeAction(id, actionType, payload);
      res.json({ success: true, data: result });
    } catch (error) {
      res.status(500).json({ success: false, error: 'Failed to execute action' });
    }
  }
}
