### Feed Service with AI Integration

```typescript
// backend/src/services/feedService.ts
import { PrismaClient, Priority, Source, ActionType } from '@prisma/client';
import { redis, socketManager } from '../app';
import { OpenAIService } from './aiService';
import { PriorityScorer } from '../utils/priorityScorer';

const prisma = new PrismaClient();
const aiService = new OpenAIService();
const priorityScorer = new PriorityScorer();

export interface FeedItemInput {
  executiveId: string;
  source: Source;
  externalId: string;
  sourceMetadata: any;
  subject: string;
  content: string;
  receivedAt: Date;
}

export class FeedService {
  async createFeedItem(input: FeedItemInput) {
    // 1. Generate AI Summary and Suggested Replies (Parallel)
    const [aiAnalysis, priorityScore] = await Promise.all([
      aiService.analyzeCommunication(input.subject, input.content),
      priorityScorer.calculateScore(input.subject, input.content, input.sourceMetadata)
    ]);

    // 2. Determine Priority
    let priority: Priority = Priority.LOW;
    if (priorityScore > 0.9) priority = Priority.CRITICAL;
    else if (priorityScore > 0.7) priority = Priority.HIGH;
    else if (priorityScore > 0.4) priority = Priority.MEDIUM;

    // 3. Determine Available Actions based on source and content
    const availableActions = this.determineActions(input.source, aiAnalysis.intent);

    // 4. Create Feed Item
    const feedItem = await prisma.feedItem.create({
      data: {
        executiveId: input.executiveId,
        source: input.source,
        externalId: input.externalId,
        sourceMetadata: input.sourceMetadata,
        subject: input.subject,
        originalContent: input.content,
        summary: aiAnalysis.summary,
        priority,
        priorityScore,
        keyEntities: aiAnalysis.entities,
        availableActions,
        receivedAt: input.receivedAt,
        suggestedReplies: {
          create: aiAnalysis.suggestedReplies.map((reply: any) => ({
            text: reply.text,
            tone: reply.tone,
            confidence: reply.confidence
          }))
        }
      },
      include: {
        suggestedReplies: true
      }
    });

    // 5. Cache and Broadcast (Real-time)
    await this.cacheAndBroadcast(feedItem);

    return feedItem;
  }

  async getExecutiveFeed(params: {
    executiveId: string;
    priority?: string;
    source?: string;
    status?: string;
    limit: number;
    offset: number;
  }) {
    const where: any = {
      executiveId: params.executiveId,
      status: params.status || 'UNREAD'
    };

    if (params.priority) where.priority = params.priority;
    if (params.source) where.source = params.source;

    const [items, total] = await Promise.all([
      prisma.feedItem.findMany({
        where,
        include: {
          suggestedReplies: {
            orderBy: { confidence: 'desc' },
            take: 3
          }
        },
        orderBy: [
          { priority: 'asc' }, // CRITICAL first
          { receivedAt: 'desc' }
        ],
        take: params.limit,
        skip: params.offset
      }),
      prisma.feedItem.count({ where })
    ]);

    return { items, total };
  }

  async executeAction(itemId: string, actionType: ActionType, payload: any) {
    const item = await prisma.feedItem.findUnique({
      where: { id: itemId }
    });

    if (!item) throw new Error('Item not found');

    // Execute specific action logic
    switch (actionType) {
      case ActionType.ARCHIVE:
        await prisma.feedItem.update({
          where: { id: itemId },
          data: { status: 'ARCHIVED' }
        });
        break;
      case ActionType.MARK_DONE:
        await prisma.feedItem.update({
          where: { id: itemId },
          data: { status: 'DONE' }
        });
        break;
      case ActionType.REPLY:
        // Integrate with Gmail/WhatsApp APIs to send reply
        await this.sendReply(item, payload);
        break;
      // Add other actions...
    }

    // Notify clients of update
    socketManager.notifyItemUpdate(item.executiveId, itemId, { status: 'DONE' });

    return { success: true, actionType };
  }

  private determineActions(source: Source, intent: string): ActionType[] {
    const baseActions: ActionType[] = [ActionType.ARCHIVE, ActionType.MARK_DONE];

    if (source === Source.GMAIL) {
      baseActions.push(ActionType.REPLY, ActionType.FORWARD);
    }

    if (intent.includes('meeting') || intent.includes('schedule')) {
      baseActions.push(ActionType.SCHEDULE_MEETING);
    }

    if (intent.includes('delegate') || intent.includes('assign')) {
      baseActions.push(ActionType.DELEGATE);
    }

    return [...new Set(baseActions)];
  }

  private async cacheAndBroadcast(item: any) {
    // Cache for quick retrieval
    await redis.setex(
      `feed:${item.executiveId}:${item.id}`,
      3600,
      JSON.stringify(item)
    );

    // Broadcast to connected clients
    socketManager.broadcastNewItem(item.executiveId, item);
  }

  private async sendReply(item: any, payload: any) {
    // Implementation depends on source (Gmail API or WhatsApp Business API)
    console.log(`Sending reply to ${item.source}:`, payload);
  }
}
